const fetchWithRetry = async (url, options = {}, maxRetries = 3) => {
  let lastError;

  for (let attempt = 1; attempt <= maxRetries; attempt++) {
    try {
      const response = await fetch(url, options);

      if (!response.ok) {
        throw new Error(`HTTP error! status: ${response.status}`);
      }

      return await response.json();
    } catch (error) {
      lastError = error;
      console.warn(`Attempt ${attempt}/${maxRetries} failed: ${error.message}`);

      if (attempt === maxRetries) break;

      // Optional: Exponential backoff could be implemented here
      await new Promise(resolve => setTimeout(resolve, 1000 * attempt));
    }
  }

  throw new Error(`Request failed after ${maxRetries} attempts. Last error: ${lastError.message}`);
};

// Ejemplo de uso:
const fetchData = async () => {
  try {
    const data = await fetchWithRetry('https://jsonplaceholder.typicode.com/posts/1');
    console.log('Success:', data);
  } catch (error) {
    console.error('Final Error:', error.message);
  }
};

fetchData();
